// app/javascript/controllers/flash_controller.js
var flash_controller_default = class extends Controller {
  dismiss() {
    this.element.remove();
  }
  connect() {
    if (this.element.classList.contains("is-success")) {
      setTimeout(() => this.element.remove(), 5e3);
    }
  }
};

// app/javascript/controllers/sidebar_controller.js
var sidebar_controller_default = class extends Controller {
  static targets = ["project", "panel", "toggleButton"];
  connect() {
    this.restorePanelState();
  }
  toggleProject(event) {
    const header = event.currentTarget;
    const project = header.closest(".sidebar-project");
    if (project) project.classList.toggle("is-open");
  }
  togglePanel(event) {
    if (event) event.preventDefault();
    const hidden = this.panelTarget.classList.toggle("is-hidden");
    this.toggleButtonTarget.classList.toggle("is-active", !hidden);
    localStorage.setItem("devteam.rightPanelHidden", hidden ? "1" : "0");
  }
  restorePanelState() {
    const stored = localStorage.getItem("devteam.rightPanelHidden");
    const hidden = stored !== "0";
    this.panelTarget.classList.toggle("is-hidden", hidden);
    this.toggleButtonTarget.classList.toggle("is-active", !hidden);
  }
};

// app/javascript/controllers/chat_controller.js
var chat_controller_default = class extends Controller {
  static targets = ["messages", "textarea"];
  connect() {
    this.scrollToBottom();
  }
  scrollToBottom() {
    const el = this.messagesTarget;
    if (el) el.scrollTop = el.scrollHeight;
  }
  // Expand textarea as user types
  autoGrow(event) {
    const ta = event.currentTarget;
    ta.style.height = "auto";
    ta.style.height = Math.min(ta.scrollHeight, 160) + "px";
  }
  // Submit on Ctrl+Enter / Cmd+Enter
  keySubmit(event) {
    if ((event.ctrlKey || event.metaKey) && event.key === "Enter") {
      event.preventDefault();
      event.currentTarget.closest("form")?.requestSubmit();
    }
  }
  // After form submission, scroll to bottom
  afterSubmit() {
    requestAnimationFrame(() => this.scrollToBottom());
  }
};

